def main():
    full_code = ''
    while True:
        try:
            while True:
                user_input = input('Do you want to progress ?(y/n)')
                if user_input.lower() == 'n':
                    break
                table_name = input('How would you like to call your table?')
                full_code += f'\ncreate table {table_name}('
                while True:
                    attribut = input('What would you like the attribut? (exit to exit)')
                    if attribut == 'exit' or attribut == '':
                        break
                    attribut_type = input('What type is the attribut?')
                    if len(attribut) >= 2:
                        if attribut[-2:].lower() in ['nr','id']:
                            if attribut_type == '':
                                attribut_type = 'int'
                    if len(attribut) >= 6:
                        if attribut[-6:].lower() == 'nummer':
                            if attribut_type == '':
                                attribut_type = 'int'
                    if len(attribut) >= 4:
                        if attribut[-4:].lower() == 'date':
                            if attribut_type == '':
                                attribut_type = 'date' 
                        elif attribut[-4:].lower() == 'zahl':
                            if attribut_type == '':
                                attribut_type = 'int'

                    if attribut[-5:].lower() == 'datum':
                            if attribut_type == '':
                                attribut_type = 'date' 

                    if attribut_type == 'str' or attribut_type == '':
                        attribut_type = 'varchar(255)'
                        
                    full_code += f'\n{attribut} {attribut_type},'
                pk = ''
                pks = ''
                while pk != 'exit':
                    pk = input('How would you like to call your pk? (exit to exit)')
                    if pk.lower() == 'exit' or pk == '' and len(pks)>0:
                        break
                    if pk == '':
                        pk = table_name + 'ID'
                    pks +=f'{pk},'
                if len(pks) > 0:
                    pks = pks[:-1]
                    full_code += f'\nprimary key({pks}),'
                fk = ''
                while fk != 'exit':
                    fk = input('How would you like to call your fk? (exit to exit)')
                    if fk == 'exit' or fk == '':
                        break
                    refernce_tbl = input('What is the reference table?')
                    if refernce_tbl == '':
                        refernce_tbl = fk[:-2]
                    full_code += f'\nforeign key({fk}) references {refernce_tbl}({fk}),'
                full_code = full_code[:-1]
                full_code += '\n);'
            print(full_code)
            break
        except KeyboardInterrupt:
            continue
        except Exception as e:
            print(e)
            print(full_code)
            break
        except:
            print(full_code)
            break
if __name__  == '__main__':
    main()
